checker_dsl:
EXISTS (`ClassInstanceExpr CIE`) {
  AND {
    EXISTS (`RefType T`) {
      AND {
        (`the type of CIE is T`),
        EXISTS (`RefType ANC`) {
          AND {
            (`ANC is an ancestor of T`),
            OR {
              (`ANC has qualified name "java.io.Reader"`),
              (`ANC has qualified name "java.io.InputStream"`),
              (`ANC has qualified name "java.util.zip.ZipFile"`)
            }
          }
        },
        NOT {
          EXISTS (`RefType SAFE_ANC`) {
            AND {
              (`SAFE_ANC is an ancestor of the type derived from CIE (which is either T or the type of a transitive closeable parent of CIE)`),
              OR {
                (`SAFE_ANC has qualified name "java.io.CharArrayReader" or "java.io.StringReader" or "java.io.ByteArrayInputStream" or name "StringInputStream"`)
              }
            }
          }
        },
        NOT {
          OR {
            AND {
              (`CIE is locally initialized (its root cause is not a parameter or field access)`),
              (`CIE is a ClassInstanceExpr`),
              NOT { EXISTS (`Expr ARG`) { (`ARG is an argument of CIE`) } }
            },
            EXISTS (`RefType SOURCE_TYPE`, `Method CLOSE_METHOD`) {
              AND {
                (`SOURCE_TYPE is the type of CIE`),
                (`SOURCE_TYPE is from source`),
                (`CLOSE_METHOD is declared in SOURCE_TYPE`),
                (`the name of CLOSE_METHOD is "close"`),
                NOT { EXISTS (`Stmt S`) { (`S is a child statement in the body of CLOSE_METHOD`) } }
              }
            },
            EXISTS (`CloseableInitExpr SQL_STMT`, `LocalVariableDecl V`) {
              AND {
                (`the type of SQL_STMT is a RefType whose ancestor is a TypeStatement`),
                (`SQL_STMT flows into variable V`),
                (`SQL_STMT is a closed resource (immediately closed or flows into a close-called variable)`),
                (`the type of CIE is a TypeResultSet`),
                (`CIE is a SqlResourceOpeningMethodCall`),
                (`the qualifier of CIE is an access to variable V`)
              }
            },
            EXISTS (`MethodCall MA`) {
              AND {
                (`MA is an argument of CIE`),
                OR {
                  (`the method of MA is a ServletResponseGetOutputStreamMethod`),
                  (`the method of MA is a ServletResponseGetWriterMethod`),
                  (`the method of MA is a ServletRequestGetBodyMethod`)
                }
              }
            },
            EXISTS (`CloseableInitExpr INNER`) {
              AND {
                (`INNER is a transitive closeable parent of CIE`),
                (`INNER satisfies the noNeedToClose condition (expanded recursively here)`)
              }
            },
            EXISTS (`CloseableInitExpr INNER2`, `LocalVariableDecl INNER_VAR`) {
              AND {
                (`INNER2 is a transitive closeable parent of CIE`),
                (`INNER2 is locally initialized`),
                (`INNER2 flows into variable INNER_VAR`),
                (`close is called on variable INNER_VAR (via try-with-resources, close method call, or parameter propagation)`)
              }
            }
          }
        },
        AND {
          OR {
            AND {
              (`CIE is locally initialized`),
              NOT { EXISTS (`Variable VAR`) { (`CIE flows into VAR`) } },
              NOT {
                EXISTS (`ClassInstanceExpr OUTER`) {
                  AND {
                    (`OUTER is locally initialized`),
                    NOT { EXISTS (`Exception EXC`) { (`EXC is an exception declared by the constructor of OUTER`) } },
                    (`CIE is an argument of OUTER`)
                  }
                }
              },
              NOT {
                EXISTS (`MethodCall CLOSE_CALL`) { AND { (`CLOSE_CALL is a call to a method named "close"`), (`the qualifier of CLOSE_CALL is CIE`) } }
              },
              NOT {
                EXISTS (`Expr WRAPPING_RES`) {
                  AND {
                    OR {
                      (`WRAPPING_RES is CIE`),
                      (`WRAPPING_RES is a transitive closeable parent of CIE`)
                    },
                    (`CIE is locally initialized`),
                    OR {
                      EXISTS (`Field F`) { (`WRAPPING_RES flows into field F`) },
                      EXISTS (`ConstructorCall CONS_CALL`) {
                        AND {
                          OR { (`CONS_CALL calls this`), (`CONS_CALL calls super`) },
                          (`the constructed type of CONS_CALL is a closeable type`),
                          (`WRAPPING_RES is an argument of CONS_CALL`)
                        }
                      },
                      (`the enclosing statement of WRAPPING_RES is a ReturnStmt`),
                      EXISTS (`LocalVariableDecl WRAP_VAR`) {
                        AND {
                          (`WRAPPING_RES is locally initialized`),
                          (`WRAPPING_RES flows into variable WRAP_VAR`),
                          (`the enclosing statement of an access to WRAP_VAR is a ReturnStmt`)
                        }
                      },
                      EXISTS (`Parameter P0`) {
                        AND {
                          (`the callable of P0 is a Method`),
                          (`the type of P0 is a closeable type`),
                          OR {
                            (`WRAPPING_RES is an argument of P0`),
                            EXISTS (`LocalVariableDecl V0`) {
                              AND {
                                (`an access to V0 is an argument of P0`),
                                (`WRAPPING_RES flows into V0`)
                              }
                            }
                          },
                          OR {
                            EXISTS (`Field F0`) { (`WRAPPING_RES flows into field F0`) },
                            EXISTS (`Parameter P1`) {
                              AND {
                                (`P1 satisfies the escapingMethodParameterClosable condition (expanded recursively)`),
                                OR {
                                  (`an argument of P1 is WRAPPING_RES`),
                                  EXISTS (`LocalVariableDecl V1`) {
                                    AND {
                                      (`an access to V1 is an argument of P1`),
                                      (`WRAPPING_RES flows into V1`)
                                    }
                                  }
                                }
                              }
                            }
                          }
                        }
                      }
                    }
                  }
                }
              }
            },
            AND {
              (`CIE is locally initialized`),
              NOT {
                OR {
                  EXISTS (`MethodCall IMM_CLOSE`) { AND { (`IMM_CLOSE is a call to a method named "close"`), (`the qualifier of IMM_CLOSE is CIE`) } },
                  EXISTS (`LocalVariableDecl CLOSE_VAR`, `Expr WRAPPING_RES2`) {
                    AND {
                      (`close is called on variable CLOSE_VAR (via try-with-resources, close method call, or parameter propagation)`),
                      OR {
                        (`WRAPPING_RES2 is CIE`),
                        (`WRAPPING_RES2 is a transitive closeable parent of CIE`)
                      },
                      (`WRAPPING_RES2 flows into variable CLOSE_VAR`)
                    }
                  }
                }
              },
              NOT {
                (`CIE satisfies the escapingCloseableInit condition (expanded as in Branch A above)`)
              }
            }
          },
          NOT {
            EXISTS (`CloseableInitExpr CIE2`) {
              AND {
                (`CIE2 is a transitive closeable parent of CIE`),
                (`CIE2 is not equal to CIE`),
                (`CIE2 satisfies the badCloseableInitImpl condition (expanded as the OR of Branch A and B above)`)
              }
            }
          }
        }
      }
    }
  }
}
